// Pattern: move useSearchParams to a client-only wrapper
// Before (causes bailout):
export default function HomePage() {
  const searchParams = useSearchParams(); // ❌ triggers CSR bailout
  return <ProductGrid category={searchParams.get('cat')} />;
}

// After: wrap in Suspense
export default function HomePage() {
  return (
    <Suspense fallback={<ProductGridSkeleton />}>
      <HomePageContent />
    </Suspense>
  );
}

